  function appendDiagRows(list, subjectId, rows){
    var base = Array.isArray(list) ? list.slice() : [];
    var before = base.length;
    var merged = uniqBy(base.concat(rows || []), function(row){
      return String(row.g || '') + '|' + norm(row.topic || '') + '|' + norm(row.q || '') + '|' + norm(row.a || '');
    });
    if (typeof QBANK !== 'undefined' && QBANK) QBANK[subjectId] = merged;
    return {
      added: Math.max(0, merged.length - before),
      total: merged.length
    };
  }
